wrong_code:
// WRONG — staticcall cannot modify state
// transferFrom writes to storage — will ALWAYS revert
let success := staticcall(
    gas(),
    tokenAddr,
    0x00,   // input offset
    0x64,   // input size
    0x00,   // output offset  
    0x20    // output size
)

correct_code:
// CORRECT — use call() for any state-changing function
// transferFrom, transfer, approve all write to storage
let success := call(
    gas(),
    tokenAddr,
    0,      // ETH value (0 for token calls)
    0x00,   // input offset
    0x64,   // input size
    0x00,   // output offset
    0x20    // output size
)

// staticcall is ONLY correct for pure view functions:
// balanceOf, allowance, totalSupply, name, symbol, decimals
let balance := staticcall(
    gas(),
    tokenAddr,
    0x00,
    0x24,
    0x00,
    0x20
)
